import{_ as i,o as t,c as s,a3 as a}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"80. Classification And Reclassification","description":"","frontmatter":{"title":"80. Classification And Reclassification","eba":"Biomedical Engineers 2025-2028","topics":["preliminary"]},"headers":[],"relativePath":"ebas/biomedical-engineers/classification-staffing/80-classification-and-reclassification.md","filePath":"ebas/biomedical-engineers/classification-staffing/80-classification-and-reclassification.md"}'),o={name:"ebas/biomedical-engineers/classification-staffing/80-classification-and-reclassification.md"};function n(r,e,c,l,p,f){return t(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="_80-classification-and-reclassification" tabindex="-1">80. Classification And Reclassification <a class="header-anchor" href="#_80-classification-and-reclassification" aria-label="Permalink to &quot;80. Classification And Reclassification&quot;">​</a></h1><p><strong>80.1</strong> Employees will be classified (including a reclassification request) as per the classification descriptors in <a href="/eba/ebas/biomedical-engineers/classification-staffing/82-classification-definitions.html">clause 82</a>.</p><p><strong>80.2</strong> The Employer shall notify each Employee in writing of their classification and terms of employment.</p><p><strong>80.3</strong> Position Description Review</p><p><strong>(a)</strong> An Employee may request a position description (PD) review at any time in writing.</p><p><strong>(b)</strong> Upon receipt of the written request, the Employer will review the Employee’s PD within 30 days with a view to ensuring it accurately reflects their role’s substantive tasks and duties.</p><p><strong>(c)</strong> If, following the review, agreement is not reached on the contents of the PD, the Employer or Employee may refer it to the dispute resolution procedure in this Agreement (<a href="/eba/ebas/allied-health/consultation-disputes/14-dispute-resolution-procedure.html">clause 14</a>).</p><p><strong>80.4</strong> Reclassification</p><p><strong>(a)</strong> Where an Employee believes that the work performed and required by their position is better described by another classification with a higher rate of pay, the Employee may seek reclassification by notifying the Employer in writing, addressing why they believe another classification better describes the work performed and required by their position, having regard to both the current and proposed classification. The Employee’s Manager may also make the reclassification request.</p><p><strong>(b)</strong> The Employer will provide a written response to the requested reclassification within four (4) weeks. Where the Employer, in accordance with subclause 80.1, does not believe the work performed and required by the Employee’s position is better described by another classification, the Employer will provide the reasons for this, having regard to both the current and proposed classification.</p><p><strong>(c)</strong> Where the Employer determines, in accordance with subclauses 80.4(a) and 80.4(b), that another classification better describes the work performed and required by the Employee’s position, the reclassification will take effect from the earlier of:</p><p><strong>(i)</strong> where it can reasonably be determined, the date on which the Employee’s work was better described by another classification; or</p><p><strong>(ii)</strong> the date the written reclassification request was submitted.</p><p><strong>(d)</strong> Reclassification of an Employee does not rely on a vacancy or funding for the position but will be determined solely in accordance with the classification descriptors at <a href="/eba/ebas/biomedical-engineers/classification-staffing/82-classification-definitions.html">clause 82</a>.</p><p><strong>(e)</strong> Nothing in this clause prevents an Employer from clarifying the requirements of an Employee’s role where an Employer becomes aware an Employee is performing work that is not required by their position.</p><p><strong>(f)</strong> Either the Employee or Employer may refer a request for reclassification to the dispute settlement procedure in <a href="/eba/ebas/allied-health/consultation-disputes/14-dispute-resolution-procedure.html">clause 14</a> of this Agreement or if unable to be resolved, the Alternative Dispute Resolution Panel (clause 0).</p>',16)])])}const m=i(o,[["render",n]]);export{h as __pageData,m as default};
